// 1. جلب كل صفوف المنافسين باستخدام الـ Syntax الجديد
const competitors = $('Get row(s) in sheet').all().map(item => {
  try {
    // التأكد من أن الحقل data موجود فعلاً
    return item.json.data ? JSON.parse(item.json.data) : null;
  } catch (e) {
    return null;
  }
}).filter(i => i !== null);

// 2. جلب بيانات تحليل شركة كيانوفا (أول نتيجة فقط)
// لاحظ استخدام $('...') هنا أيضاً لضمان الاستقرار
const myBusiness = $('Analysis My Business').item.json.data;

// 3. دمج البيانات في آيتم واحد يروح للايجنت
return {
  combined_data: {
    target_brand: myBusiness,
    competitors_market_data: competitors,
    total_competitors_analyzed: competitors.length
  }
};

// Input Validation and Routing Logic
const rawInput = $input.item.json;

// Webhook wraps POST body in 'body' property
// Support both direct input and body-wrapped input
const input = rawInput.body || rawInput;

// Determine input type
let inputType = 'unknown';
let inputData = null;
let isValid = false;
let errorMessage = null;

// Check for URL input
if (input.url && typeof input.url === 'string') {
  const urlPattern = /^https?:\/\/.+/i;
  if (urlPattern.test(input.url.trim())) {
    inputType = 'url';
    inputData = input.url.trim();
    isValid = true;
  } else {
    errorMessage = 'Invalid URL format. URL must start with http:// or https://';
  }
}
// Check for document/file input (base64 encoded)
else if (input.fileData || input.documentData || input.pdfData) {
  const fileData = input.fileData || input.documentData || input.pdfData;
  inputType = 'document';
  inputData = fileData;
  isValid = true;
}
// Check for raw text input (for pre-extracted content)
else if (input.textContent && typeof input.textContent === 'string') {
  inputType = 'text';
  inputData = input.textContent;
  isValid = true;
}
else {
  errorMessage = 'No valid input provided. Please provide either a URL or document data.';
}

return {
  inputType,
  inputData,
  isValid,
  errorMessage,
  searchQuery: input.searchQuery || input.industry || 'AI Automation Agency',
  brandName: input.brandName || 'Subject Brand',
  originalInput: input
};

// Extract and clean text from document input
const input = $input.item.json;
let cleanedText = '';

if (input.inputType === 'document') {
  // If base64 encoded, decode and extract text
  // For now, we'll assume the text has been pre-extracted
  cleanedText = input.inputData;
} else if (input.inputType === 'text') {
  cleanedText = input.inputData;
}

// Clean the text
cleanedText = cleanedText
  .replace(/\s+/g, ' ')  // Normalize whitespace
  .replace(/[\r\n]+/g, '\n')  // Normalize line breaks
  .trim();

return {
  extractedText: cleanedText,
  inputType: input.inputType,
  searchQuery: input.searchQuery,
  brandName: input.brandName
};

// Standardize analysis output from either URL or Document path
const items = $input.all();
let analysisData = null;
let inputType = 'unknown';
let brandName = 'Subject Brand';
let searchQuery = 'AI Automation Agency';

for (const item of items) {
  if (item.json.data) {
    // From Firecrawl URL analysis
    analysisData = item.json.data;
    inputType = 'url';
  } else if (item.json.output) {
    // From Document analysis agent
    analysisData = item.json.output;
    inputType = 'document';
  }

  if (item.json.searchQuery) searchQuery = item.json.searchQuery;
  if (item.json.brandName) brandName = item.json.brandName;
}

return {
  business_analysis: analysisData,
  inputType,
  searchQuery,
  brandName
};

const answerBox = $input.item.json.answerBox ? [$input.item.json.answerBox] : [];
const organic = $input.item.json.organic || [];
return {
  json: {
    all_results: answerBox.concat(organic)
  }
};

// Collect all competitor analysis data
const items = $input.all();
const competitorData = items.map(item => {
  return {
    name: item.json.name || 'Unknown',
    url: item.json.url || '',
    analysis: item.json.data || item.json
  };
});

return {
  competitors_analyzed: competitorData,
  total_count: competitorData.length
};

// Combine business analysis with competitor data for Master Strategist
const businessAnalysis = $('Standardize Analysis Output1').first().json;
const competitorData = $input.item.json;

return {
  combined_data: {
    target_brand: businessAnalysis.business_analysis,
    brand_name: businessAnalysis.brandName,
    competitors_market_data: competitorData.competitors_analyzed,
    total_competitors_analyzed: competitorData.total_count
  }
};

